            for t in triples:
                if t.subject == genre_obj:
                    if t.predicate == "stylisticOrigin":
                        phrase += f", which originated from {lc(t.object)}"
                    elif t.predicate == "derivative":
                        phrase += f", a derivative of {lc(t.object)}"
                    elif t.predicate == "musicFusionGenre":
                        phrase += f", a music fusion genre of {lc(t.object)}"
                    elif t.predicate == "musicSubgenre":
                        phrase += f", a subgenre of {lc(t.object)}"
